class Solution {
    public boolean digitCount(String num) {
        for (int i = 0; i < num.length(); i++) {
            if (Character.getNumericValue(num.charAt(i)) != String.valueOf(num.charAt(i)).chars().filter(c -> c == Character.getNumericValue(num.charAt(i))).count()) {
                return false;
            }
        }
        return true;
    }
}
